	"golang.org/x/crypto/bcrypt"
	_ "modernc.org/sqlite"
)

type app struct{ db *sql.DB; secret []byte; sitesRoot string }
type ctxKey string
const userIDKey ctxKey = "uid"

type business struct{ ID int64 `json:"id"`; Name,Category,City,Address,Phone,Website,Status string `json:"name,omitempty"`; Score int `json:"score"`; PotentialMonthlyRevenue int `json:"potential_monthly_revenue"`; Notes string `json:"notes"` }

type jmap map[string]any

func main(){
	dbPath:=env("DB_PATH","./data/local-business-os.db"); _=os.MkdirAll(filepath.Dir(dbPath),0755)
	db,err:=sql.Open("sqlite",dbPath); if err!=nil{log.Fatal(err)}
	a:=&app{db:db, secret:[]byte(env("SESSION_SECRET","dev-change-me-local-business-os")), sitesRoot:env("GENERATED_SITES_ROOT","./generated-sites")}
	if err:=a.initDB(); err!=nil{log.Fatal(err)}
	mux:=http.NewServeMux(); a.routes(mux)
	addr:=env("ADDR",":8080"); log.Printf("Local Business OS Indonesia API listening on %s",addr); log.Fatal(http.ListenAndServe(addr, logReq(cors(mux))))
}

func env(k,d string) string{ if v:=os.Getenv(k); v!=""{return v}; return d }
func writeJSON(w http.ResponseWriter, code int, v any){ w.Header().Set("Content-Type","application/json"); w.WriteHeader(code); _=json.NewEncoder(w).Encode(v) }
func readJSON(r *http.Request, v any) error{ defer r.Body.Close(); return json.NewDecoder(io.LimitReader(r.Body,1<<20)).Decode(v) }
func logReq(next http.Handler) http.Handler{return http.HandlerFunc(func(w http.ResponseWriter,r *http.Request){log.Printf("%s %s",r.Method,r.URL.Path); next.ServeHTTP(w,r)})}
func cors(next http.Handler) http.Handler{return http.HandlerFunc(func(w http.ResponseWriter,r *http.Request){o:=r.Header.Get("Origin"); if strings.HasPrefix(o,"http://localhost")||strings.HasPrefix(o,"http://127.0.0.1"){w.Header().Set("Access-Control-Allow-Origin",o); w.Header().Set("Access-Control-Allow-Credentials","true"); w.Header().Set("Access-Control-Allow-Headers","Content-Type,X-CSRF-Token"); w.Header().Set("Access-Control-Allow-Methods","GET,POST,OPTIONS")}; if r.Method=="OPTIONS"{w.WriteHeader(204); return}; next.ServeHTTP(w,r)})}

func (a *app) routes(m *http.ServeMux){
	m.HandleFunc("/healthz", func(w http.ResponseWriter,r *http.Request){writeJSON(w,200,jmap{"ok":true,"service":"local-business-os-indonesia"})})
	m.HandleFunc("/api/v1/locales/", a.handleLocale)
	m.HandleFunc("/api/v1/auth/login", a.handleLogin)
	m.Handle("/api/v1/auth/logout", a.auth(http.HandlerFunc(a.handleLogout)))
	m.Handle("/api/v1/auth/me", a.auth(http.HandlerFunc(a.handleMe)))
	m.Handle("/api/v1/dashboard/summary", a.auth(http.HandlerFunc(a.handleSummary)))
	m.Handle("/api/v1/businesses", a.auth(http.HandlerFunc(a.handleBusinesses)))
	m.Handle("/api/v1/businesses/", a.auth(http.HandlerFunc(a.handleBusinessSub)))
	m.Handle("/api/v1/imports", a.auth(http.HandlerFunc(a.handleImports)))
	m.Handle("/api/v1/scan-jobs", a.auth(http.HandlerFunc(a.handleScanJobs)))
	m.Handle("/api/v1/opportunities", a.auth(http.HandlerFunc(a.handleOpportunities)))
	m.Handle("/api/v1/leads", a.auth(http.HandlerFunc(a.handleLeads)))
	m.Handle("/api/v1/website-drafts", a.auth(http.HandlerFunc(a.handleDrafts)))
	m.Handle("/api/v1/website-drafts/", a.auth(http.HandlerFunc(a.handleDraftSub)))
	m.Handle("/api/v1/market-reports", a.auth(http.HandlerFunc(a.handleReports)))
}

func (a *app) initDB() error{
	stmts:=[]string{`PRAGMA foreign_keys=ON`,
`CREATE TABLE IF NOT EXISTS users(id INTEGER PRIMARY KEY, email TEXT UNIQUE NOT NULL, username TEXT UNIQUE NOT NULL, password_hash TEXT NOT NULL, role TEXT NOT NULL DEFAULT 'owner', created_at TEXT NOT NULL)`,
`CREATE TABLE IF NOT EXISTS sessions(id TEXT PRIMARY KEY, user_id INTEGER NOT NULL, token_hash TEXT NOT NULL, csrf_token TEXT NOT NULL, expires_at TEXT NOT NULL, created_at TEXT NOT NULL, FOREIGN KEY(user_id) REFERENCES users(id))`,
`CREATE TABLE IF NOT EXISTS businesses(id INTEGER PRIMARY KEY, name TEXT NOT NULL, category TEXT NOT NULL, city TEXT NOT NULL, address TEXT, phone TEXT, website TEXT, status TEXT NOT NULL DEFAULT 'prospect', score INTEGER NOT NULL DEFAULT 0, potential_monthly_revenue INTEGER NOT NULL DEFAULT 0, notes TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL, UNIQUE(name,city,category))`,
`CREATE TABLE IF NOT EXISTS business_snapshots(id INTEGER PRIMARY KEY, business_id INTEGER NOT NULL, source TEXT NOT NULL, rating REAL, review_count INTEGER, has_website INTEGER, social_links TEXT, raw_json TEXT, created_at TEXT NOT NULL, FOREIGN KEY(business_id) REFERENCES businesses(id))`,
`CREATE TABLE IF NOT EXISTS leads(id INTEGER PRIMARY KEY, business_id INTEGER, contact_name TEXT, channel TEXT, value INTEGER, stage TEXT, next_action TEXT, created_at TEXT NOT NULL, FOREIGN KEY(business_id) REFERENCES businesses(id))`,
`CREATE TABLE IF NOT EXISTS imports(id INTEGER PRIMARY KEY, source TEXT, status TEXT, total_rows INTEGER, inserted_rows INTEGER, duplicate_rows INTEGER, errors TEXT, created_at TEXT NOT NULL)`,
`CREATE TABLE IF NOT EXISTS scan_jobs(id INTEGER PRIMARY KEY, city TEXT, category TEXT, query TEXT, status TEXT, safeguards TEXT, collected_count INTEGER, sample_json TEXT, created_at TEXT NOT NULL)`,
`CREATE TABLE IF NOT EXISTS website_drafts(id INTEGER PRIMARY KEY, business_id INTEGER NOT NULL, title TEXT, slug TEXT UNIQUE, html TEXT, status TEXT, deployed_path TEXT, public_url TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL, FOREIGN KEY(business_id) REFERENCES businesses(id))`,
`CREATE TABLE IF NOT EXISTS market_reports(id INTEGER PRIMARY KEY, city TEXT, category TEXT, title TEXT, summary TEXT, metrics_json TEXT, created_at TEXT NOT NULL)`}
	for _,s:=range stmts{ if _,err:=a.db.Exec(s); err!=nil{return err} }
	var n int; _=a.db.QueryRow(`SELECT COUNT(*) FROM users`).Scan(&n); if n==0{ h,_:=bcrypt.GenerateFromPassword([]byte("balikpapan123"),bcrypt.DefaultCost); _,err:=a.db.Exec(`INSERT INTO users(email,username,password_hash,role,created_at) VALUES(?,?,?,?,?)`,"admin@localbiz.id","admin",string(h),"owner",now()); if err!=nil{return err}}
	_ = a.seed(); return nil
}
func now() string{return time.Now().UTC().Format(time.RFC3339)}
func (a *app) seed() error{var n int; _=a.db.QueryRow(`SELECT COUNT(*) FROM businesses`).Scan(&n); if n>0{return nil}; samples:=[]business{{Name:"Kopi Teluk Balikpapan",Category:"Kafe",City:"Balikpapan",Address:"Jl. Jenderal Sudirman",Phone:"0812-1000-2000",Status:"prospect",Score:82,PotentialMonthlyRevenue:4500000,Notes:"Belum punya website, ulasan kuat."},{Name:"Bengkel Prima Sepinggan",Category:"Bengkel",City:"Balikpapan",Address:"Sepinggan",Phone:"0812-2222-3333",Website:"",Status:"qualified",Score:76,PotentialMonthlyRevenue:6000000},{Name:"Salon Cantik Damai",Category:"Salon",City:"Balikpapan",Address:"Damai",Phone:"0813-8888-9000",Score:69,PotentialMonthlyRevenue:3000000},{Name:"Warung Makan Beruang Madu",Category:"Restoran",City:"Balikpapan",Address:"Gunung Bahagia",Phone:"0542-555777",Score:88,PotentialMonthlyRevenue:7500000}}; for _,b:=range samples{res,_:=a.db.Exec(`INSERT OR IGNORE INTO businesses(name,category,city,address,phone,website,status,score,potential_monthly_revenue,notes,created_at,updated_at) VALUES(?,?,?,?,?,?,?,?,?,?,?,?)`,b.Name,b.Category,b.City,b.Address,b.Phone,b.Website,coalesce(b.Status,"prospect"),b.Score,b.PotentialMonthlyRevenue,b.Notes,now(),now()); id,_:=res.LastInsertId(); a.db.Exec(`INSERT INTO business_snapshots(business_id,source,rating,review_count,has_website,social_links,raw_json,created_at) VALUES(?,?,?,?,?,?,?,?)`,id,"seed",4.4,80,b.Website!="","[]","{}",now())}; a.db.Exec(`INSERT INTO leads(business_id,contact_name,channel,value,stage,next_action,created_at) VALUES(1,'Ibu Rina','WhatsApp',4500000,'new','Kirim audit gratis',?)`,now()); a.db.Exec(`INSERT INTO market_reports(city,category,title,summary,metrics_json,created_at) VALUES('Balikpapan','UMKM','Peluang Digital UMKM Balikpapan','Banyak bisnis lokal kuat di ulasan namun belum memiliki website cepat dan katalog online.',?,?)`,`{"avgScore":79,"topCategories":["Kafe","Bengkel","Restoran"]}`,now()); return nil}
func coalesce(v,d string) string{if v==""{return d}; return v}

func (a *app) sign(s string) string{m:=hmac.New(sha256.New,a.secret); m.Write([]byte(s)); return hex.EncodeToString(m.Sum(nil))}
func randToken() string{b:=make([]byte,32); rand.Read(b); return base64.RawURLEncoding.EncodeToString(b)}
func hashToken(t string) string{h:=sha256.Sum256([]byte(t)); return hex.EncodeToString(h[:])}
func (a *app) auth(next http.Handler) http.Handler{return http.HandlerFunc(func(w http.ResponseWriter,r *http.Request){c,err:=r.Cookie("lbos_session"); if err!=nil{writeJSON(w,401,jmap{"error":"unauthorized"});return}; parts:=strings.Split(c.Value,"."); if len(parts)!=2 || !hmac.Equal([]byte(a.sign(parts[0])),[]byte(parts[1])){writeJSON(w,401,jmap{"error":"bad_session"});return}; var uid int64; var csrf,exp string; err=a.db.QueryRow(`SELECT user_id,csrf_token,expires_at FROM sessions WHERE token_hash=?`,hashToken(parts[0])).Scan(&uid,&csrf,&exp); if err!=nil{writeJSON(w,401,jmap{"error":"session_not_found"});return}; et,_:=time.Parse(time.RFC3339,exp); if time.Now().After(et){writeJSON(w,401,jmap{"error":"session_expired"});return}; if r.Method!="GET" && r.Method!="HEAD"{ if r.Header.Get("X-CSRF-Token")!=csrf{writeJSON(w,403,jmap{"error":"csrf_required"});return} }; next.ServeHTTP(w,r.WithContext(contextWithUser(r.Context(),uid)))})}

// tiny context helpers avoid extra framework
func contextWithUser(ctx interface{ Done() <-chan struct{} }, uid int64) any { return nil }
